import re
from typing import Any

# Constants inferred from snippets
_VALID_CHANNELS = {"alpha", "beta", "gamma"}
_CHANNEL_NORMALIZER = {"alpha": 100, "beta": 10, "gamma": 1}
_TOKEN_PATTERN = re.compile(r'^[A-Z][0-9]$')

def token_value(token: str) -> int:
    """Compute the numeric value of a token (letter + digit)."""
    if not _TOKEN_PATTERN.match(token):
        raise ValueError(f"Invalid token: {token!r}")
    letter = token[0]
    digit = int(token[1])
    # Letter value: A=1, B=2, ..., Z=26
    letter_val = ord(letter) - ord('A') + 1
    return letter_val * 10 + digit

def split_fluxon_payload(payload: str) -> list[str]:
    """Split a dash-separated payload into tokens."""
    return payload.split('-') if payload else []

def normalize_channel_value(raw: float, channel: str) -> float:
    """Normalize a raw numeric value according to the channel."""
    if channel not in _VALID_CHANNELS:
        raise ValueError(f"Invalid channel: {channel}")
    return raw / _CHANNEL_NORMALIZER[channel]

def solve(packet: str) -> float:
    """Return the normalized token-sum for a valid packet, else -1.0.

    Packet format: '<channel>:<dash-separated-tokens>'
    e.g. 'alpha:A1-B2-C3'
    """
    try:
        # Split channel and payload
        if ':' not in packet:
            return -1.0
        channel, payload = packet.split(':', 1)
        channel = channel.strip()
        if channel not in _VALID_CHANNELS:
            return -1.0

        # Split payload into tokens
        tokens = split_fluxon_payload(payload)
        if not tokens:
            # Empty payload is valid, sum = 0
            raw_sum = 0
        else:
            raw_sum = sum(token_value(t) for t in tokens)

        return normalize_channel_value(raw_sum, channel)
    except (ValueError, AttributeError):
        return -1.0
