import re

def solve(series: str) -> int:
    # Define helper functions inside solve to avoid external dependencies
    _TOKEN_PATTERN = re.compile(r'^[A-G][0-9]$')

    def nimbla_value(token: str) -> float:
        if not _TOKEN_PATTERN.match(token):
            raise ValueError(f"Invalid Nimbla token: {token!r}")
        letter_index = ord(token[0]) - ord('A') + 1
        digit = int(token[1])
        return letter_index + digit / 10.0

    def _token_from_value(value: float) -> str:
        letter_index = int(value)
        digit = round((value - letter_index) * 10)
        if not (1 <= letter_index <= 7 and 0 <= digit <= 9):
            raise ValueError(f"Invalid value: {value}")
        return chr(ord('A') + letter_index - 1) + str(digit)

    # Parse the input series string
    if not series.startswith('NIM|'):
        raise ValueError("Invalid series string")
    content = series[4:]
    if not content:
        timestamps = []
        values = []
    else:
        entries = content.split(',')
        timestamps = []
        values = []
        for entry in entries:
            ts_str, token = entry.split(':')
            timestamps.append(int(ts_str))
            values.append(nimbla_value(token))

    # Format back to a Nimbla series string
    formatted = "NIM|" + ",".join(
        f"{ts}:{_token_from_value(val)}" for ts, val in zip(timestamps, values)
    )

    # Parse the formatted string again
    if not formatted.startswith('NIM|'):
        raise ValueError("Invalid formatted series")
    content2 = formatted[4:]
    if not content2:
        count = 0
    else:
        count = len(content2.split(','))

    return count
