            raise ValueError(f"Invalid entry: {token!r}")
        ts_str, nimbla_token = token.split(':', 1)
        timestamps.append(int(ts_str))
        values.append(nimbla_value(nimbla_token))

    # Forecast next value using mean method
    next_value = forecast_next({"values": values}, method="mean")

    # Determine next timestamp
    if len(timestamps) >= 2:
        step = timestamps[-1] - timestamps[-2]
    else:
        step = 1  # default step for a single point
    next_ts = timestamps[-1] + step

    # Append
    timestamps.append(next_ts)
    values.append(next_value)

    # Format and return
    return format_nimbla_series(timestamps, values)
