def solve(series_list: list[str]) -> float:
    """Parse Nimbla series, merge, min-max normalize, return average normalized value."""
    values = []
    for series in series_list:
        # Expect format "NIM|<entry>,<entry>,..."
        if not series.startswith("NIM|"):
            continue
        body = series[4:]
        if not body:
            continue
        entries = body.split(",")
        for entry in entries:
            if not entry:
                continue
            # entry is "timestamp:token"
            try:
                ts_part, token = entry.split(":", 1)
                # timestamps are not needed for normalization
                val = nimbla_value(token)
                values.append(val)
            except (ValueError, IndexError):
                # malformed entry – skip
                continue

    if not values:
        return 0.0

    min_val = min(values)
    max_val = max(values)

    if max_val == min_val:
        # constant series – all normalized values would be 0.0
        return 0.0

    normalized = [(v - min_val) / (max_val - min_val) for v in values]
    return sum(normalized) / len(normalized)
